import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithQuote_char() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        // Test with a normal quote char
        char quoteChar = '"';
        CSVFormat newFormat = baseFormat.withQuote(quoteChar);
        assertNotNull(newFormat);
        assertEquals(Character.valueOf(quoteChar), newFormat.getQuoteCharacter());

        // Test with a different quote char
        quoteChar = '\'';
        newFormat = baseFormat.withQuote(quoteChar);
        assertNotNull(newFormat);
        assertEquals(Character.valueOf(quoteChar), newFormat.getQuoteCharacter());

        // Test with a control character as quote char
        quoteChar = '\n';
        newFormat = baseFormat.withQuote(quoteChar);
        assertNotNull(newFormat);
        assertEquals(Character.valueOf(quoteChar), newFormat.getQuoteCharacter());

        // Test with zero char (null char)
        quoteChar = '\0';
        newFormat = baseFormat.withQuote(quoteChar);
        assertNotNull(newFormat);
        assertEquals(Character.valueOf(quoteChar), newFormat.getQuoteCharacter());

        // Test that original format is not mutated
        assertEquals(Character.valueOf(CSVFormat.DEFAULT.getQuoteCharacter()), CSVFormat.DEFAULT.getQuoteCharacter());
    }
}
